import { CSSResult, unsafeCSS } from "lit";
import { basePath } from "./paths";

/**
 * Find absolute path to asset.
 *
 * @param path path to asset from source root
 * @returns absolute path to asset
 */
export function assetPath(path: string): string {
    return new URL(path, basePath).href;
}

/**
 * Create absolute path to asset to be embedded in CSS.
 *
 * @param path path to asset from source root
 * @returns absolute path to asset
 */
export function cssAssetPath(path: string): CSSResult {
    return unsafeCSS(assetPath(path));
}
